import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"AI 绘画由哪些部分组成","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/components.md","filePath":"concepts/components.md","lastUpdated":1782223980000}'),o={name:"concepts/components.md"};function s(n,a,r,p,h,d){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="ai-绘画由哪些部分组成" tabindex="-1">AI 绘画由哪些部分组成 <a class="header-anchor" href="#ai-绘画由哪些部分组成" aria-label="Permalink to &quot;AI 绘画由哪些部分组成&quot;">​</a></h1><p>一句话：AI 绘画不是只有一个模型，而是由模型、编码器、采样流程、提示词和辅助模块共同完成。</p><h2 id="核心组成" tabindex="-1">核心组成 <a class="header-anchor" href="#核心组成" aria-label="Permalink to &quot;核心组成&quot;">​</a></h2><h3 id="底模" tabindex="-1">底模 <a class="header-anchor" href="#底模" aria-label="Permalink to &quot;底模&quot;">​</a></h3><p>底模负责生成能力本身。它决定图片风格、知识范围、分辨率习惯和生态兼容性。</p><h3 id="文本编码器" tabindex="-1">文本编码器 <a class="header-anchor" href="#文本编码器" aria-label="Permalink to &quot;文本编码器&quot;">​</a></h3><p>文本编码器负责把提示词变成模型能理解的数字表示。不同模型可能使用不同文本编码器，例如 CLIP、T5、Qwen 系编码器等。</p><p>如果文本编码器缺失或不匹配，模型可能无法正确理解提示词，甚至工作流直接报错。</p><h3 id="vae" tabindex="-1">VAE <a class="header-anchor" href="#vae" aria-label="Permalink to &quot;VAE&quot;">​</a></h3><p>VAE 负责在模型内部的潜空间和人眼可见的图片之间转换。</p><p>直观理解：</p><ul><li>编码：把图片压缩成模型内部能处理的 latent。</li><li>解码：把 latent 还原成图片。</li></ul><p>VAE 不合适时，可能出现颜色发灰、对比度异常、细节不自然等问题。</p><h3 id="采样器" tabindex="-1">采样器 <a class="header-anchor" href="#采样器" aria-label="Permalink to &quot;采样器&quot;">​</a></h3><p>采样器决定去噪过程怎么走。常见采样器包括 Euler、Euler a、DPM++ 等。</p><p>同一个提示词和模型，采样器不同，画面细节、稳定性和随机感都可能不同。</p><h3 id="调度器" tabindex="-1">调度器 <a class="header-anchor" href="#调度器" aria-label="Permalink to &quot;调度器&quot;">​</a></h3><p>调度器控制每一步去噪时噪声强度如何变化。它经常和采样器一起出现。</p><p>初学者可以先使用教程或模型页面推荐的组合，不必一开始逐个穷举。</p><h3 id="prompt" tabindex="-1">Prompt <a class="header-anchor" href="#prompt" aria-label="Permalink to &quot;Prompt&quot;">​</a></h3><p>Prompt 是提示词，告诉模型你想要什么。它通常分为：</p><ul><li>正向提示词：希望出现的内容。</li><li>负向提示词：希望减少或避免的内容。</li></ul><p>Prompt 不是命令，更像引导。模型不一定完全服从。</p><h3 id="lora" tabindex="-1">LoRA <a class="header-anchor" href="#lora" aria-label="Permalink to &quot;LoRA&quot;">​</a></h3><p>LoRA 是小型附加模型，用来给底模增加某种特征，例如角色、画风、服装、构图、材质或动作。</p><p>LoRA 需要匹配底模生态，不是所有模型都能通用。</p><h3 id="controlnet" tabindex="-1">ControlNet <a class="header-anchor" href="#controlnet" aria-label="Permalink to &quot;ControlNet&quot;">​</a></h3><p>ControlNet 用于加强控制，例如让图片遵循边缘图、深度图、姿势骨架、线稿或分割图。</p><p>它适合解决“构图和姿势不听话”的问题。</p><h3 id="工作流" tabindex="-1">工作流 <a class="header-anchor" href="#工作流" aria-label="Permalink to &quot;工作流&quot;">​</a></h3><p>工作流是把以上模块连起来的执行流程。在 ComfyUI 里，工作流通常表现为节点图。</p><p>同一个模型可以有很多工作流：文生图、图生图、局部重绘、放大修复、参考图控制等。</p><h2 id="一个最小文生图流程" tabindex="-1">一个最小文生图流程 <a class="header-anchor" href="#一个最小文生图流程" aria-label="Permalink to &quot;一个最小文生图流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[&quot;提示词&quot;] --&gt; B[&quot;文本编码器&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[&quot;采样器 / 去噪过程&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D[&quot;底模&quot;] --&gt; C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; E[&quot;Latent 图像&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E --&gt; F[&quot;VAE 解码&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  F --&gt; G[&quot;最终图片&quot;]</span></span></code></pre></div><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>把 VAE 当作底模下载。VAE 不能单独生成图片。</li><li>把 LoRA 当作 checkpoint。LoRA 需要挂在底模上使用。</li><li>以为工作流能解决所有问题。工作流只是流程，模型能力仍然是基础。</li><li>忽略文本编码器。新模型常常需要特定文本编码器。</li></ul>`,36)])])}const E=t(o,[["render",s]]);export{u as __pageData,E as default};
